+}
+
+#[test]
+fn nss_hesiod_getservbyport_r_returns_notfound_and_sets_errno() {
+    use frankenlibc_abi::unistd_abi::_nss_hesiod_getservbyport_r;
+    let proto = CString::new("tcp").unwrap();
